var e=[{id:`L1_1`,type:`dialog`,speaker:null,text:{ENG:` --`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`LEADER_NPC_MINING_NULL`,text:{KOREA:`음?`,JPN:`む？`,ENG:`Mm?`,TWN:`嗯？`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LEADER_NPC_MINING_NULL`,text:{KOREA:`관제탑, 여기는 채굴팀.`,JPN:`管制塔、こちら採掘チーム。`,ENG:`Control Tower, this is the Mining Team.`,TWN:`塔台，這裡是採礦組。`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`LEADER_NPC_MINING_NULL`,text:{KOREA:`방금 함선 한 척이 착륙하던데, 오늘 근무교대 예정이 있었나?`,JPN:`先ほど艦船一隻が着陸していたが、今日勤務交代の予定があったのか？`,ENG:`A ship just has landed. Are we changing shifts today?`,TWN:`剛才有一艘艦船著陸，今天有預計要交接嗎？`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`OPERATOR_NPC_MINING_NULL`,text:{KOREA:`<color=#ffd34c>여기는 관제탑. 이쪽에서도 미확인 함선의 다이브 아웃을 관측했다.</color>`,JPN:`<color=#ffd34c>こちら管制塔。こちらでも未確認艦船のダイブアウトを観測した。</color>`,ENG:`<color=#ffd34c>This is the Control Tower. We've observed the unidentified ship's Dive-out.</color>`,TWN:`<color=#ffd34c>這裡是塔台，塔台也觀測到有不知名的艦船躍出。</color>`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`OPERATOR_NPC_MINING_NULL`,text:{KOREA:`<color=#ffd34c>차원 불안정 주기라 교대인원이 올 가능성은 없어.</color>`,JPN:`<color=#ffd34c>次元不安定周期のため、交代人員が来る可能性はない。</color>`,ENG:`<color=#ffd34c>Dimensions are unstable at this time. No way this is a shift change.</color>`,TWN:`<color=#ffd34c>但現在正處於次元不穩定週期，不可能會有人員來交接。</color>`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`OPERATOR_NPC_MINING_NULL`,text:{KOREA:`<color=#ffd34c>좀 낯익은 모델 같은데, 경계수준 유지하면서 대기해.</color>`,JPN:`<color=#ffd34c>どうも見慣れたモデルみたいだが、警戒レベルを維持しつつ待機せよ。</color>`,ENG:`<color=#ffd34c>That model looks a bit familiar. Stay alert.</color>`,TWN:`<color=#ffd34c>型號有點陌生，保持戒備狀態。</color>`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`OPERATOR_NPC_MINING_NULL`,text:{KOREA:`<color=#ffd34c>잠깐, 근처에서 또 다이브 진입 신호가……</color>`,JPN:`<color=#ffd34c>待て、近くでまたダイブ進入信号が……</color>`,ENG:`<color=#ffd34c>Wait, we've got signals for another Dive-out nearby—</color>`,TWN:`<color=#ffd34c>等等，附近也傳來躍入的信號……</color>`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:null,text:{KOREA:`과, 관제탑이 무너진다!`,JPN:`か、管制塔が崩れ落ちる！`,ENG:`Th-the Control Tower is falling!`,TWN:`塔…塔台倒塌了！`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`LEADER_NPC_MINING_NULL`,text:{KOREA:`이런 미친놈들……! 다짜고짜 함포를 쏘다니!`,JPN:`そんなバカな……！　いきなり艦砲を撃ちやがって！`,ENG:`Those wackos! They fired their ship cannon!`,TWN:`這群瘋子……！竟然就這樣發射艦砲！`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`PIRATE_NPC_SAILOR_A`,text:{KOREA:`세금 징수원이 도착했어, 친구들.`,JPN:`やあ、税金徴収係の到着だぜ。`,ENG:`The tax collectors have arrived, fellas.`,TWN:`朋友們～我來收保護費囉！`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`PIRATE_NPC_SAILOR_A`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`PIRATE_NPC_SAILOR_A`,text:{KOREA:`댁들이 열심히 일해 줘서 우리도 참 기분이 좋아.`,JPN:`おたくらが一生懸命に働いてくれて俺らもとても嬉しい。`,ENG:`Thank you for working so hard for us.`,TWN:`看到你們這麼認真工作，我們也很開心。`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`PIRATE_NPC_SAILOR_A`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`LEADER_NPC_MINING_NULL`,text:{KOREA:`다, 당신들 지금 제정신이야?`,JPN:`あ、あんたたち正気か？`,ENG:`A-are you out of your mind?`,TWN:`你…你們好大的膽子？！`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`LEADER_NPC_MINING_NULL`,text:{KOREA:`여긴 알파트릭스 그룹이 독점하는 채굴 구역이다! 보안팀이 오면 너희들은 끝장이야!`,JPN:`ここはアルファトリックスグループが独占する採掘区域だ！　警備チームが来たら全員タダでは済まないぞ！`,ENG:`This mining concession belongs to the Alphatrix Group! You'd better leave before the security team gets here!`,TWN:`這裡可是阿爾法崔克斯集團專屬的開採區！等保安組的人來你們就完蛋了！`},stage:{bg:`COUNTERSIDE_BASE_NIGHT`,slots:{L:null,C:{char_id:`LEADER_NPC_MINING_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};